"#!/usr/bin/env bash\nset -euo pipefail\n\n# Sprint 1 Test Runner\n# Frontend (Lexer + Parser) Stabilization Tests\n\nROOT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")/..\" && pwd)\"\ncd \"$ROOT_DIR\"\n\nSOUC_BIN=\"${SOUC_BIN:-./souc}\"\nLOG_DIR=\"${LOG_DIR:-/tmp/sounio-sprint1-tests}\"\nARTIFACT_DIR=\"$LOG_DIR/artifacts\"\nSUMMARY_FILE=\"$ARTIFACT_DIR/summary.json\"\n\nTIMEOUT_SECS=30\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\npass() {\n    echo -e \"${GREEN}✓${NC} $1\"\n}\n\nfail() {\n    echo -e \"${RED}✗${NC} $1\"\n}\n\ninfo() {\n    echo -e \"${YELLOW}ℹ${NC} $1\"\n}\n\nrun_test() {\n    local test_file=\"$1\"\n    local test_name=\"$2\"\n    local log_file=\"$LOG_DIR/${test_name}.log\"\n    \n    echo \"Running $test_name...\" > \"$log_file\"\n    \n    set +e\n    timeout --preserve-status \"${TIMEOUT_SECS}s\" \\\n        \"$SOUC_BIN\" run \"$test_file\" >> \"$log_file\" 2>&1\n    local exit_code=$?\n    set -e\n    \n    if [ $exit_code -eq 0 ]; then\n        pass \"$test_name\"\n        echo \"PASS\" >> \"$log_file\"\n        return 0\n    elif [ $exit_code -eq 124 ]; then\n        fail \"$test_name (timeout after ${TIMEOUT_SECS}s)\"\n        echo \"TIMEOUT\" >> \"$log_file\"\n        return 1\n    else\n        fail \"$test_name (exit code: $exit_code)\"\n        echo \"FAIL (exit: $exit_code)\" >> \"$log_file\"\n        return 1\n    fi\n}\n\n# Create directories\nmkdir -p \"$LOG_DIR\" \"$ARTIFACT_DIR\"\n\n# Start summary\ncat > \"$SUMMARY_FILE\" <<EOF\n{\n  \"sprint\": 1,\n  \"goal\": \"Frontend Stabilization\",\n  \"start_time\": \"$(date -u +'%Y-%m-%dT%H:%M:%SZ')\",\n  \"tests\": {\n    \"lexer\": {},\n    \"parser\": {},\n    \"integration\": {},\n    \"performance\": {},\n    \"fuzz\": {}\n  },\n  \"results\": {\n    \"total\": 0,\n    \"passed\": 0,\n    \"failed\": 0,\n    \"skipped\": 0\n  }\n}\nEOF\n\nupdate_summary() {\n    local key=\"$1\"\n    local value=\"$2\"\n    \n    python3 -c \"\nimport json\nimport sys\n\nwith open('$SUMMARY_FILE', 'r') as f:\n    data = json.load(f)\n\n# Navigate and update\nkeys = '$key'.split('.')\ntarget = data\nfor k in keys[:-1]:\n    if k not in target:\n        target[k] = {}\n    target = target[k]\n\nlast_key = keys[-1]\ntry:\n    # Try to parse as JSON if it looks like JSON\n    if '$value'.startswith('{') or '$value'.startswith('['):\n        target[last_key] = json.loads('$value')\n    else:\n        target[last_key] = '$value'\nexcept:\n    target[last_key] = '$value'\n\nwith open('$SUMMARY_FILE', 'w') as f:\n    json.dump(data, f, indent=2)\n\" 2>/dev/null || true\n}\n\nincrement_result() {\n    local result_type=\"$1\"\n    update_summary \"results.$result_type\" \"\\$((\\\$(python3 -c \\\"import json; with open('$SUMMARY_FILE') as f: d=json.load(f); print(d['results']['$result_type'])\\\") + 1))\"\n    update_summary \"results.total\" \"\\$((\\\$(python3 -c \\\"import json; with open('$SUMMARY_FILE') as f: d=json.load(f); print(d['results']['total'])\\\") + 1))\"\n}\n\n# Check if souc binary exists\nif [ ! -x \"$SOUC_BIN\" ]; then\n    fail \"Compiler binary not found or not executable: $SOUC_BIN\"\n    exit 1\nfi\n\ninfo \"Starting Sprint 1 Tests\"\ninfo \"Compiler: $SOUC_BIN\"\ninfo \"Log directory: $LOG_DIR\"\n\n# ============================================================================\n# LEXER TESTS\n# ============================================================================\n\ninfo \"\\n=== Phase 1: Lexer Tests ===\"\n\nLEXER_TESTS=(\n    \"tests/frontend/lexer_integration.sio\"\n)\n\nlexer_passed=0\nlexer_failed=0\n\nfor test_file in \"${LEXER_TESTS[@]}\"; do\n    if [ ! -f \"$test_file\" ]; then\n        info \"Skipping missing test: $test_file\"\n        continue\n    fi\n    \n    test_name=\"$(basename \"$test_file\" .sio)\"\n    \n    if run_test \"$test_file\" \"lexer_$test_name\"; then\n        increment_result \"passed\"\n        update_summary \"tests.lexer.$test_name\" \"pass\"\n        ((lexer_passed++))\n    else\n        increment_result \"failed\"\n        update_summary \"tests.lexer.$test_name\" \"fail\"\n        ((lexer_failed++))\n    fi\n    \n    # Add small delay between tests\n    sleep 0.1\n\ndone\n\n# ============================================================================\n# PARSER TESTS (placeholder for now)\n# ============================================================================\n\ninfo \"\\n=== Phase 2: Parser Tests ===\"\n\nPARSER_TESTS=(\n    # Will be added when parser tests are created\n)\n\nparser_passed=0\nparser_failed=0\n\nfor test_file in \"${PARSER_TESTS[@]}\"; do\n    if [ ! -f \"$test_file\" ]; then\n        continue\n    fi\n    \n    test_name=\"$(basename \"$test_file\" .sio)\"\n    \n    if run_test \"$test_file\" \"parser_$test_name\"; then\n        increment_result \"passed\"\n        update_summary \"tests.parser.$test_name\" \"pass\"\n        ((parser_passed++))\n    else\n        increment_result \"failed\"\n        update_summary \"tests.parser.$test_name\" \"fail\"\n        ((parser_failed++))\n    fi\n    \n    sleep 0.1\ndone\n\n# ============================================================================\n# EXISTING TESTS\n# ============================================================================\n\ninfo \"\\n=== Phase 3: Existing Selfhost Tests ===\"\n\nEXISTING_TESTS=(\n    \"self-hosted/test_lexer.sio\"\n    \"self-hosted/test_parser.sio\"\n)\n\nexisting_passed=0\nexisting_failed=0\n\nfor test_file in \"${EXISTING_TESTS[@]}\"; do\n    if [ ! -f \"$test_file\" ]; then\n        info \"Skipping missing test: $test_file\"\n        continue\n    fi\n    \n    test_name=\"$(basename \"$test_file\" .sio)\"\n    \n    if run_test \"$test_file\" \"existing_$test_name\"; then\n        increment_result \"passed\"\n        update_summary \"tests.integration.$test_name\" \"pass\"\n        ((existing_passed++))\n    else\n        increment_result \"failed\"\n        update_summary \"tests.integration.$test_name\" \"fail\"\n        ((existing_failed++))\n    fi\n    \n    sleep 0.1\ndone\n\n# ============================================================================\n# SUMMARY\n# ============================================================================\n\nupdate_summary \"end_time\" \"$(date -u +'%Y-%m-%dT%H:%M:%SZ')\"\n\n# Calculate totals from summary\nTOTAL_PASSED=$(python3 -c \"import json; with open('$SUMMARY_FILE') as f: d=json.load(f); print(d['results']['passed'])\" 2>/dev/null || echo \"0\")\nTOTAL_FAILED=$(python3 -c \"import json; with open('$SUMMARY_FILE') as f: d=json.load(f); print(d['results']['failed'])\" 2>/dev/null || echo \"0\")\nTOTAL_TESTS=$(python3 -c \"import json; with open('$SUMMARY_FILE') as f: d=json.load(f); print(d['results']['total'])\" 2>/dev/null || echo \"0\")\n\ninfo \"\\n=== Sprint 1 Test Summary ===\"\necho \"Lexer Tests:    $lexer_passed passed, $lexer_failed failed\"\necho \"Parser Tests:   $parser_passed passed, $parser_failed failed\"\necho \"Existing Tests: $existing_passed passed, $existing_failed failed\"\necho \"Total:          $TOTAL_PASSED passed, $TOTAL_FAILED failed of $TOTAL_TESTS tests\"\n\n# Copy summary to artifacts directory\ncp \"$SUMMARY_FILE\" \"artifacts/sprint1_test_summary.json\" 2>/dev/null || true\n\n# Final status\nif [ \"$TOTAL_FAILED\" -eq 0 ] && [ \"$TOTAL_TESTS\" -gt 0 ]; then\n    pass \"All tests passed!\"\n    exit 0\nelse\n    fail \"Some tests failed. See logs in $LOG_DIR\"\n    \n    # Show failing test logs\n    if [ \"$TOTAL_FAILED\" -gt 0 ]; then\n        echo \"\\nFailed test logs:\"\n        grep -l \"FAIL\\|TIMEOUT\" \"$LOG_DIR\"/*.log 2>/dev/null | head -5 | while read log; do\n            echo \"  $(basename \"$log\" .log):\"\n            tail -5 \"$log\" | sed 's/^/    /'\n        done\n    fi\n    \n    exit 1\nfi\n"